// Extract L1 assets and fan out one message per asset to fetch their children
const response = msg.payload || {};
const assets = response._embedded?.assets || response._embedded?.asset || [];

if (assets.length === 0) {
    node.warn('No L1 assets found');
    return null;
}

// Return an array of messages - Node-RED sends each as a separate message
// msg.parts tells the downstream join node how many to expect
const msgs = assets.map((asset, i) => ({
    payload: asset,
    mindspherePath: `/api/assetmanagement/v3/assets?filter={"parentId":"${asset.assetId}"}&size=200`,
    parts: { id: msg._msgid, index: i, count: assets.length, type: 'array' }
}));

return [msgs];

// Store the asset mapping in flow variable for use in other parts
const assetMap = msg.payload.assetMap || {};
const assetsList = msg.payload.assetsList || [];

flow.set('assetNameToIdMap', assetMap);
flow.set('assetsList', assetsList);

msg.payload = {
    message: 'Asset mapping stored in flow variables',
    totalAssets: Object.keys(assetMap).length,
    assetNames: Object.keys(assetMap),
    mapping: assetMap
};

return msg;

// Normalize a string for fuzzy matching:
//  - lowercase
//  - replace '(' with '_'
//  - remove ')'
//  - collapse consecutive underscores to one
//  - trim leading/trailing underscores
function normalize(str) {
    return str
        .toLowerCase()
        .replace(/\(/g, '_')
        .replace(/\)/g, '')
        .replace(/([0-9])\.([0-9])/g, function(m, a, b) { return a + '_' + b; })
        .replace(/_+/g, '_')
        .replace(/^_+|_+$/g, '');
}

// Load asset map populated by the second flow
const assetNameToIdMap = flow.get('assetNameToIdMap');
if (!assetNameToIdMap) {
    node.warn('assetNameToIdMap not found - run "Load Asset Mapping" first');
    return null;
}

// Build a normalized reverse-lookup: normalizedName -> { originalName, assetId }
const normalizedAssetMap = {};
Object.entries(assetNameToIdMap).forEach(([name, assetId]) => {
    // Strip any accidental file extensions from asset names (e.g. '.csv' data quirk)
    const cleaned = name.replace(/\.(csv|json|xls[xm]?)$/i, '');
    const key = normalize(cleaned);
    normalizedAssetMap[key] = { originalName: name, assetId };
});

// Process the file list from IDL
const fileList = Array.isArray(msg.payload) ? msg.payload : [];
const matched = [];
const unmatched = [];

fileList.forEach(file => {
    const key = file.key || '';
    // Skip folder entries (zero-byte entries ending with '/')
    if (!key || key.endsWith('/') || file.contentSize === 0) return;

    const filename = key.split('/').pop(); // e.g. 'counter_linea_t.16_tart.rocher__m.6.json'
    const stripped = filename
        .replace(/^counter_/i, '')          // remove 'counter_' prefix
        .replace(/\.json$/i, '');           // remove '.json' suffix

    const normalizedFilename = normalize(stripped);
    const match = normalizedAssetMap[normalizedFilename];

    if (match) {
        matched.push({
            filename,
            key,
            assetName: match.originalName,
            assetId: match.assetId,
            contentSize: file.contentSize,
            lastModified: file.lastModified
        });
    } else {
        unmatched.push({
            filename,
            key,
            normalizedKey: normalizedFilename,
            contentSize: file.contentSize
        });
    }
});

flow.set('matchedFiles', matched);

msg.payload = {
    matched,
    unmatched,
    matchedCount: matched.length,
    unmatchedCount: unmatched.length
};

return msg;

// msg.payload is array of L2 HTTP responses (one per PU)
const responses = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
const l2Assets = [];

responses.forEach(response => {
    const assets = response._embedded?.assets || response._embedded?.asset || [];
    assets.forEach(asset => {
        if (asset.name && asset.assetId) {
            l2Assets.push({
                name: asset.name,
                assetId: asset.assetId,
                typeId: asset.typeId,
                parentId: asset.parentId
            });
        }
    });
});

// Persist L2 assets for later combination with L3 results
flow.set('l2Assets', l2Assets);

if (l2Assets.length === 0) {
    node.warn('No L2 assets found');
    return null;
}

// Fan out one request per L2 asset to fetch its children (L3)
const msgs = l2Assets.map((asset, i) => ({
    payload: asset,
    mindspherePath: `/api/assetmanagement/v3/assets?filter={"parentId":"${asset.assetId}"}&size=200`,
    parts: { id: msg._msgid, index: i, count: l2Assets.length, type: 'array' }
}));

return [msgs];

// msg.payload is array of L3 HTTP responses (one per L2 asset queried)
const l2Assets = flow.get('l2Assets') || [];
const responses = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
const l3Assets = [];

responses.forEach(response => {
    const assets = response._embedded?.assets || response._embedded?.asset || [];
    assets.forEach(asset => {
        if (asset.name && asset.assetId) {
            l3Assets.push({
                name: asset.name,
                assetId: asset.assetId,
                typeId: asset.typeId,
                parentId: asset.parentId
            });
        }
    });
});

// Combine L2 and L3 into one flat mapping
const allAssets = [...l2Assets, ...l3Assets];
const mapping = {};
const namesList = [];

allAssets.forEach(asset => {
    if (!mapping[asset.name]) {
        mapping[asset.name] = asset.assetId;
        namesList.push(asset);
    }
});

msg.payload = {
    assetMap: mapping,
    assetsList: namesList,
    totalCount: namesList.length,
    l2Count: l2Assets.length,
    l3Count: l3Assets.length
};

return msg;
